// Insert the key into the Trie and update the count of each node accordingly.
function insertNodeIntoTrie(trie, key) {
    if (key === '') return trie;
    let node = trie;
    for (let char of key) {
        if (!node.children[char]) {
            node.children[char] = {
                children: {},
                count: 1
            };
        } else {
            node.children[char].count++;
        }
        node = node.children[char];
    }
    node.count = 1;
    return trie;
}
